import type { Project, SortOrder, GalleryQuery } from './types'

const DATA_PATH = `${import.meta.dir}/data/projects.json`

const loadProjects = async (): Promise<Project[]> => {
  const file = Bun.file(DATA_PATH)
  const raw = await file.json()
  return raw as Project[]
}

const sortProjects = (projects: Project[], order: SortOrder): Project[] => {
  const sorted = [...projects]
  switch (order) {
    case 'date-desc':
      return sorted.sort((a, b) => new Date(b.dateAdded).getTime() - new Date(a.dateAdded).getTime())
    case 'date-asc':
      return sorted.sort((a, b) => new Date(a.dateAdded).getTime() - new Date(b.dateAdded).getTime())
    case 'alpha-asc':
      return sorted.sort((a, b) => a.title.localeCompare(b.title))
    case 'alpha-desc':
      return sorted.sort((a, b) => b.title.localeCompare(a.title))
  }
}

export const queryProjects = async (query: GalleryQuery): Promise<Project[]> => {
  let projects = await loadProjects()

  if (query.tag) {
    const tag = query.tag.toLowerCase()
    projects = projects.filter((p) => p.tags.some((t) => t.toLowerCase() === tag))
  }

  if (query.q) {
    const q = query.q.toLowerCase()
    projects = projects.filter((p) => p.title.toLowerCase().includes(q))
  }

  const order = query.sort ?? 'date-desc'
  projects = sortProjects(projects, order)

  return projects
}

export const getProject = async (slug: string): Promise<Project | undefined> => {
  const projects = await loadProjects()
  return projects.find((p) => p.slug === slug)
}

export const getAllTags = async (): Promise<string[]> => {
  const projects = await loadProjects()
  const tagSet = new Set<string>()
  for (const p of projects) {
    for (const t of p.tags) {
      tagSet.add(t)
    }
  }
  return [...tagSet].sort()
}

