import { h, Fragment } from 'plaited'
import { createSSR } from 'plaited/server'
import type { Project, SortOrder, GalleryQuery } from './types'
import { styles } from './styles'

const styleAttr = (obj: Record<string, string | number | undefined>): string =>
  Object.entries(obj)
    .filter(([, v]) => v !== undefined)
    .map(([k, v]) => {
      const prop = k.replace(/[A-Z]/g, (c) => `-${c.toLowerCase()}`)
      return `${prop}:${typeof v === 'number' ? `${v}px` : v}`
    })
    .join(';')

const formatDate = (iso: string): string => {
  const d = new Date(iso)
  return d.toLocaleDateString('en-US', { year: 'numeric', month: 'short', day: 'numeric' })
}

const renderTagFilters = (allTags: string[], activeTag?: string) =>
  h(
    'div',
    { style: styleAttr(styles.tagFilters) },
    h(
      'button',
      {
        style: styleAttr(activeTag ? styles.tagButton : styles.tagButtonActive),
        'p-trigger': 'click:filter-tag',
        'data-tag': '',
      },
      'All',
    ),
    ...allTags.map((tag) =>
      h(
        'button',
        {
          style: styleAttr(activeTag?.toLowerCase() === tag.toLowerCase() ? styles.tagButtonActive : styles.tagButton),
          'p-trigger': 'click:filter-tag',
          'data-tag': tag,
        },
        tag,
      ),
    ),
  )

const renderProjectCard = (project: Project) =>
