    h('img', {
      src: project.thumbnail,
      alt: project.title,
      style: styleAttr(styles.cardThumbnail),
      loading: 'lazy',
    }),
    h(
      'div',
      { style: styleAttr(styles.cardBody) },
      h('h3', { style: styleAttr(styles.cardTitle) }, project.title),
      h('p', { style: styleAttr(styles.cardSummary) }, project.summary),
      h(
        'div',
        { style: styleAttr(styles.cardTags) },
        ...project.tags.map((tag) => h('span', { style: styleAttr(styles.cardTag) }, tag)),
      ),
      h(
        'div',
        { style: styleAttr(styles.cardLinks) },
        h('span', { style: styleAttr(styles.cardLink) }, 'Live Demo'),
        h('span', { style: styleAttr(styles.cardLink) }, 'Source'),
