      h('div', { style: styleAttr(styles.cardDate) }, formatDate(project.dateAdded)),
    ),
  )

export const renderGallery = (projects: Project[], allTags: string[], query: GalleryQuery): string => {
  const { ssr } = createSSR()
  const currentSort = query.sort ?? 'date-desc'

  const template = h(
    'div',
    { style: styleAttr(styles.page) },
    h(
      'header',
      { style: styleAttr(styles.header) },
      h('h1', { style: styleAttr(styles.title) }, 'Portfolio'),
      h('p', { style: styleAttr(styles.subtitle) }, 'A collection of projects and experiments'),
    ),
    h(
      'div',
      { style: styleAttr(styles.controls), 'p-target': 'controls' },
      h('input', {
        type: 'text',
        placeholder: 'Search projects by title\u2026',
        value: query.q ?? '',
        style: styleAttr(styles.searchInput),
        'p-trigger': 'input:search',
        'p-target': 'search-input',
      }),
      h(
        'select',
        {
          style: styleAttr(styles.select),
          'p-trigger': 'change:sort',
          'p-target': 'sort-select',
        },
        h('option', { value: 'date-desc', ...(currentSort === 'date-desc' ? { selected: '' } : {}) }, 'Newest First'),
        h('option', { value: 'date-asc', ...(currentSort === 'date-asc' ? { selected: '' } : {}) }, 'Oldest First'),
        h('option', { value: 'alpha-asc', ...(currentSort === 'alpha-asc' ? { selected: '' } : {}) }, 'A \u2192 Z'),
        h('option', { value: 'alpha-desc', ...(currentSort === 'alpha-desc' ? { selected: '' } : {}) }, 'Z \u2192 A'),
      ),
    ),
    renderTagFilters(allTags, query.tag),
    projects.length > 0
      ? h(
          'div',
          { style: styleAttr(styles.grid), 'p-target': 'project-grid' },
          ...projects.map(renderProjectCard),
        )
      : h(
          'div',
          { style: styleAttr(styles.emptyState) },
          h('p', {}, 'No projects found matching your criteria.'),
        ),
  )

  return ssr(template)
}

const renderLightbox = (images: string[], activeIndex: number) =>
  h(
    'div',
    { style: styleAttr(styles.lightbox), 'p-target': 'lightbox' },
    h('img', {
      src: images[activeIndex],
      alt: `Image ${activeIndex + 1}`,
      style: styleAttr(styles.lightboxImage),
      'p-target': 'lightbox-image',
    }),
    images.length > 1
      ? h(
          Fragment,
          {},
          h(
            'div',
            { style: styleAttr(styles.lightboxControls) },
            h(
              'button',
              {
                style: styleAttr(styles.lightboxButton),
                'p-trigger': 'click:lightbox-prev',
                disabled: activeIndex === 0 ? '' : undefined,
              },
              '\u2190 Prev',
            ),
            h(
              'span',
              { style: styleAttr(styles.lightboxCounter), 'p-target': 'lightbox-counter' },
              `${activeIndex + 1} / ${images.length}`,
            ),
            h(
              'button',
              {
                style: styleAttr(styles.lightboxButton),
                'p-trigger': 'click:lightbox-next',
                disabled: activeIndex === images.length - 1 ? '' : undefined,
              },
              'Next \u2192',
            ),
          ),
          h(
            'div',
            { style: styleAttr(styles.thumbnailStrip) },
            ...images.map((img, i) =>
              h('img', {
                src: img,
                alt: `Thumbnail ${i + 1}`,
                style: styleAttr(i === activeIndex ? styles.thumbnailStripImgActive : styles.thumbnailStripImg),
                'p-trigger': 'click:lightbox-goto',
                'data-index': String(i),
              }),
            ),
          ),
        )
      : null,
  )

export const renderDetail = (project: Project, imageIndex: number = 0): string => {
  const { ssr } = createSSR()

  const template = h(
    'div',
    { style: styleAttr(styles.page) },
    h(
      'a',
      { href: '/', style: styleAttr(styles.detailBack), 'p-trigger': 'click:back-to-gallery' },
      '\u2190 Back to Gallery',
    ),
    h('h1', { style: styleAttr(styles.detailTitle) }, project.title),
    h('div', { style: styleAttr(styles.detailDate) }, `Added ${formatDate(project.dateAdded)}`),
    h(
      'div',
      { style: styleAttr(styles.detailTags) },
      ...project.tags.map((tag) =>
        h('span', { style: styleAttr(styles.cardTag) }, tag),
      ),
    ),
    h(
      'div',
      { style: styleAttr(styles.detailLinks) },
      h(
        'a',
        {
          href: project.demoUrl,
          target: '_blank',
          rel: 'noopener noreferrer',
          style: styleAttr({ ...styles.detailLink, ...styles.demoBtnStyle }),
        },
        'Live Demo',
      ),
      h(
        'a',
        {
          href: project.sourceUrl,
          target: '_blank',
          rel: 'noopener noreferrer',
          style: styleAttr({ ...styles.detailLink, ...styles.sourceBtnStyle }),
        },
        'Source Code',
      ),
    ),
    h('p', { style: styleAttr(styles.detailDescription) }, project.description),
    project.images.length > 0 ? renderLightbox(project.images, imageIndex) : null,
  )

  return ssr(template)
}

import type { GalleryQuery, SortOrder } from './types'
import { queryProjects, getProject, getAllTags } from './store'
import { renderGallery, renderDetail } from './render'

const VALID_SORTS: SortOrder[] = ['date-desc', 'date-asc', 'alpha-asc', 'alpha-desc']

const parseSortOrder = (value: string | null): SortOrder | undefined => {
  if (value && VALID_SORTS.includes(value as SortOrder)) {
    return value as SortOrder
  }
  return undefined
}

const handleGallery = async (url: URL): Promise<Response> => {
  const query: GalleryQuery = {
    tag: url.searchParams.get('tag') ?? undefined,
    q: url.searchParams.get('q') ?? undefined,
    sort: parseSortOrder(url.searchParams.get('sort')),
  }

  const [projects, allTags] = await Promise.all([queryProjects(query), getAllTags()])

  const html = renderGallery(projects, allTags, query)
  return new Response(html, {
    headers: { 'Content-Type': 'text/html; charset=utf-8' },
  })
}

const handleDetail = async (slug: string, imageIndex: number): Promise<Response> => {
  const project = await getProject(slug)
  if (!project) {
    return new Response('Project not found', { status: 404 })
  }

  const clampedIndex = Math.max(0, Math.min(imageIndex, project.images.length - 1))
  const html = renderDetail(project, clampedIndex)
  return new Response(html, {
    headers: { 'Content-Type': 'text/html; charset=utf-8' },
  })
}

export const handleRequest = async (request: Request): Promise<Response> => {
  const url = new URL(request.url)

  const view = url.searchParams.get('view')
  if (view === 'detail') {
    const slug = url.searchParams.get('slug') ?? ''
    const imageIndex = parseInt(url.searchParams.get('img') ?? '0', 10) || 0
    return handleDetail(slug, imageIndex)
  }

  return handleGallery(url)
}

export default {
  port: 3000,
  fetch: handleRequest,
}

{
  "name": "@node/portfolio-gallery",
  "version": "1.0.0",
  "description": "A responsive portfolio gallery with project cards, filtering, search, sorting, and lightbox detail views",
  "modnet": {
    "contentType": "art",
    "structure": "collection",
    "mechanics": ["sort", "filter"],
    "boundary": "all",
    "scale": 2
  },
  "dependencies": {
    "plaited": "latest"
  }
}

import type { Project, SortOption, GalleryFilters } from './types'

const DATA_PATH = new URL('./data/projects.json', import.meta.url).pathname

export const loadProjects = async (): Promise<Project[]> => {
  const file = Bun.file(DATA_PATH)
  const text = await file.text()
  return JSON.parse(text) as Project[]
}

export const saveProjects = async (projects: Project[]): Promise<void> => {
  await Bun.write(DATA_PATH, JSON.stringify(projects, null, 2))
}

export const sortProjects = (projects: Project[], sort: SortOption): Project[] => {
  const sorted = [...projects]
  switch (sort) {
    case 'date-desc':
      return sorted.sort((a, b) => new Date(b.dateAdded).getTime() - new Date(a.dateAdded).getTime())
    case 'date-asc':
      return sorted.sort((a, b) => new Date(a.dateAdded).getTime() - new Date(b.dateAdded).getTime())
    case 'alpha-asc':
      return sorted.sort((a, b) => a.title.localeCompare(b.title))
    case 'alpha-desc':
      return sorted.sort((a, b) => b.title.localeCompare(a.title))
  }
}

export const filterProjects = (projects: Project[], filters: GalleryFilters): Project[] => {
  let result = [...projects]

  if (filters.tag) {
    const tag = filters.tag.toLowerCase()
    result = result.filter((p) => p.tags.some((t) => t.toLowerCase() === tag))
  }

  if (filters.search) {
    const query = filters.search.toLowerCase()
    result = result.filter((p) => p.title.toLowerCase().includes(query))
  }

  return sortProjects(result, filters.sort)
}

export const getAllTags = (projects: Project[]): string[] => {
  const tagSet = new Set<string>()
  for (const project of projects) {
    for (const tag of project.tags) {
      tagSet.add(tag)
    }
  }
  return [...tagSet].sort()
}

export const getProjectById = (projects: Project[], id: string): Project | undefined =>
  projects.find((p) => p.id === id)

