// Client-side script for interactive gallery behavior
// Injected as inline <script> in the rendered HTML

export const galleryClientScript = `
(function() {
  // --- Search with debounce ---
  const searchInput = document.querySelector('[p-target="searchInput"]');
  if (searchInput) {
    let timeout;
    searchInput.addEventListener('input', function(e) {
      clearTimeout(timeout);
      timeout = setTimeout(function() {
        const params = new URLSearchParams(window.location.search);
        const val = e.target.value.trim();
        if (val) {
          params.set('search', val);
        } else {
          params.delete('search');
        }
        window.location.search = params.toString();
      }, 400);
    });
  }

  // --- Sort select ---
  const sortSelect = document.querySelector('[p-target="sortSelect"]');
  if (sortSelect) {
    sortSelect.addEventListener('change', function(e) {
      const params = new URLSearchParams(window.location.search);
      params.set('sort', e.target.value);
      window.location.search = params.toString();
    });
  }

  // --- Tag filter buttons ---
  document.querySelectorAll('[p-trigger]').forEach(function(el) {
    try {
      const triggers = JSON.parse(el.getAttribute('p-trigger'));

      if (triggers.click === 'filterByTag') {
        el.addEventListener('click', function() {
          const tag = el.getAttribute('data-tag');
          const params = new URLSearchParams(window.location.search);
          params.set('tag', tag);
          window.location.search = params.toString();
        });
      }

      if (triggers.click === 'clearFilter') {
        el.addEventListener('click', function() {
          const params = new URLSearchParams(window.location.search);
          params.delete('tag');
          window.location.search = params.toString();
        });
      }
    } catch(e) {}
  });

  // --- Carousel ---
  const carouselImage = document.querySelector('[p-target="carouselImage"]');
  if (carouselImage) {
    const images = JSON.parse(document.getElementById('carousel-data')?.textContent || '[]');
    let currentIndex = 0;

    const updateImage = function(idx) {
      currentIndex = idx;
      carouselImage.src = images[idx];
      const dots = document.querySelectorAll('[p-target="indicators"] button');
      dots.forEach(function(dot, i) {
        dot.style.backgroundColor = i === idx ? '#ffffff' : 'rgba(255,255,255,0.4)';
      });
    };

    document.querySelectorAll('[p-trigger]').forEach(function(el) {
      try {
        const triggers = JSON.parse(el.getAttribute('p-trigger'));

        if (triggers.click === 'prevImage') {
          el.addEventListener('click', function(e) {
            e.stopPropagation();
            updateImage((currentIndex - 1 + images.length) % images.length);
          });
        }

        if (triggers.click === 'nextImage') {
          el.addEventListener('click', function(e) {
            e.stopPropagation();
            updateImage((currentIndex + 1) % images.length);
          });
        }

        if (triggers.click === 'goToImage') {
          el.addEventListener('click', function() {
            const idx = parseInt(el.getAttribute('data-index'), 10);
            updateImage(idx);
          });
        }

        if (triggers.click === 'openLightbox') {
          el.addEventListener('click', function() {
            const lightbox = document.getElementById('lightbox');
            const lightboxImg = document.getElementById('lightbox-img');
            if (lightbox && lightboxImg) {
              lightboxImg.src = images[currentIndex];
              lightbox.style.display = 'flex';
            }
          });
        }

        if (triggers.click === 'closeLightbox') {
          el.addEventListener('click', function(e) {
            if (e.target.tagName === 'IMG') return;
            document.getElementById('lightbox').style.display = 'none';
          });
        }
      } catch(e) {}
    });

    // Keyboard navigation
    document.addEventListener('keydown', function(e) {
      const lightbox = document.getElementById('lightbox');
      if (e.key === 'Escape' && lightbox) {
        lightbox.style.display = 'none';
      }
      if (e.key === 'ArrowLeft') {
        updateImage((currentIndex - 1 + images.length) % images.length);
      }
      if (e.key === 'ArrowRight') {
        updateImage((currentIndex + 1) % images.length);
      }
    });
  }

  // --- Card hover effect ---
  document.querySelectorAll('a[href^="/project/"]').forEach(function(card) {
    card.addEventListener('mouseenter', function() {
      card.style.transform = 'translateY(-4px)';
      card.style.boxShadow = '0 12px 24px rgba(0,0,0,0.3)';
    });
    card.addEventListener('mouseleave', function() {
      card.style.transform = 'translateY(0)';
      card.style.boxShadow = 'none';
    });
  });
})();
`

