const parseSort = (val: string | null): SortOption => {
  const valid: SortOption[] = ['date-desc', 'date-asc', 'alpha-asc', 'alpha-desc']
  return valid.includes(val as SortOption) ? (val as SortOption) : 'date-desc'
}

const server = Bun.serve({
  port: Number(process.env.PORT) || 3000,

  fetch: async (req) => {
    const url = new URL(req.url)
    const path = url.pathname

    // --- API endpoint ---
    if (path === '/api/projects') {
      const projects = await loadProjects()
      const filters: GalleryFilters = {
        tag: url.searchParams.get('tag') ?? undefined,
        search: url.searchParams.get('search') ?? undefined,
        sort: parseSort(url.searchParams.get('sort')),
      }
      const filtered = filterProjects(projects, filters)
      return new Response(JSON.stringify(filtered), {
        headers: { 'Content-Type': 'application/json' },
      })
    }

    // --- Detail page ---
    const projectMatch = path.match(/^\/project\/([a-z0-9-]+)$/)
    if (projectMatch) {
      const projects = await loadProjects()
      const project = getProjectById(projects, projectMatch[1])

      if (!project) {
        const content = ssr.render(renderNotFound())
        return new Response(wrapPage(content), {
          status: 404,
          headers: { 'Content-Type': 'text/html' },
        })
      }

      const content = ssr.render(renderDetail(project))
      const carouselData = `<script id="carousel-data" type="application/json">${JSON.stringify(project.images)}</script>`
      return new Response(wrapPage(content, carouselData), {
        headers: { 'Content-Type': 'text/html' },
      })
    }

    // --- Gallery page (index) ---
    if (path === '/' || path === '') {
      const projects = await loadProjects()
      const allTags = getAllTags(projects)
      const filters: GalleryFilters = {
        tag: url.searchParams.get('tag') ?? undefined,
        search: url.searchParams.get('search') ?? undefined,
        sort: parseSort(url.searchParams.get('sort')),
      }
      const filtered = filterProjects(projects, filters)
      const content = ssr.render(renderGallery(filtered, allTags, filters))
      return new Response(wrapPage(content), {
        headers: { 'Content-Type': 'text/html' },
      })
    }

    // --- 404 ---
    return new Response('Not Found', { status: 404 })
  },
})

