import type { Project, SortOption, GalleryFilters } from './types'

const DATA_PATH = './data/projects.json'

const readProjects = async (): Promise<Project[]> => {
  const file = Bun.file(DATA_PATH)
  const exists = await file.exists()
  if (!exists) return []
  return file.json()
}

const writeProjects = async (projects: Project[]): Promise<void> => {
  await Bun.write(DATA_PATH, JSON.stringify(projects, null, 2))
}

const sortProjects = (projects: Project[], sort: SortOption): Project[] => {
  const sorted = [...projects]
  switch (sort) {
    case 'date-desc':
      return sorted.sort((a, b) => new Date(b.dateAdded).getTime() - new Date(a.dateAdded).getTime())
    case 'date-asc':
      return sorted.sort((a, b) => new Date(a.dateAdded).getTime() - new Date(b.dateAdded).getTime())
    case 'alpha-asc':
      return sorted.sort((a, b) => a.title.localeCompare(b.title))
    case 'alpha-desc':
      return sorted.sort((a, b) => b.title.localeCompare(a.title))
  }
}

const filterProjects = (projects: Project[], filters: GalleryFilters): Project[] => {
  let result = projects

  if (filters.search) {
    const query = filters.search.toLowerCase()
    result = result.filter((p) => p.title.toLowerCase().includes(query))
  }

  if (filters.tag) {
    const tag = filters.tag
    result = result.filter((p) => p.tags.some((t) => t.toLowerCase() === tag.toLowerCase()))
  }

  return sortProjects(result, filters.sort)
}

const getAllTags = (projects: Project[]): string[] => {
  const tagSet = new Set<string>()
  for (const project of projects) {
    for (const tag of project.tags) {
      tagSet.add(tag)
    }
  }
  return Array.from(tagSet).sort()
}

const getProjectById = async (id: string): Promise<Project | undefined> => {
  const projects = await readProjects()
  return projects.find((p) => p.id === id)
}

const addProject = async (project: Project): Promise<void> => {
  const projects = await readProjects()
  projects.push(project)
  await writeProjects(projects)
}

const removeProject = async (id: string): Promise<boolean> => {
  const projects = await readProjects()
  const index = projects.findIndex((p) => p.id === id)
  if (index === -1) return false
  projects.splice(index, 1)
  await writeProjects(projects)
  return true
}

