export { renderGallery, renderDetail, renderNotFound, renderCarousel }

import type { GalleryFilters, SortOption } from './types'
import { readProjects, filterProjects, getAllTags, getProjectById } from './store'
import { renderGallery, renderDetail, renderNotFound } from './render'
import { createSSR } from 'plaited'

const validSorts: SortOption[] = ['date-desc', 'date-asc', 'alpha-asc', 'alpha-desc']

const parseSortParam = (value: string | null): SortOption => {
  if (value && validSorts.includes(value as SortOption)) return value as SortOption
  return 'date-desc'
}

const wrapHtml = (body: string, title: string): string => `<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>${title}</title>
  <style>
    *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }
    a { color: inherit; }
    img { max-width: 100%; }
    body { margin: 0; }
  </style>
</head>
<body>${body}
<script>
(function() {
  const carousel = document.querySelector('[p-target="carousel"]');
  if (!carousel) return;
  const track = carousel.querySelector('[p-target="track"]');
  if (!track) return;
  const images = track.querySelectorAll('img');
  const dots = carousel.querySelectorAll('[p-trigger*="dot-"]');
  const total = images.length;
  let current = 0;
  const update = () => {
    track.style.transform = 'translateX(-' + (current * 100) + '%)';
    dots.forEach((d, i) => {
      d.style.backgroundColor = i === current ? '#ffffff' : 'rgba(255,255,255,0.35)';
    });
  };
  const prev = carousel.querySelector('[p-trigger="click:prev"]');
  const next = carousel.querySelector('[p-trigger="click:next"]');
  if (prev) prev.addEventListener('click', () => { current = (current - 1 + total) % total; update(); });
  if (next) next.addEventListener('click', () => { current = (current + 1) % total; update(); });
  dots.forEach((d, i) => {
    d.addEventListener('click', () => { current = i; update(); });
  });
})();
</script>
</body>
</html>`

const handleGalleryRequest = async (url: URL): Promise<Response> => {
  const search = url.searchParams.get('search') || ''
  const tag = url.searchParams.get('tag') || null
  const sort = parseSortParam(url.searchParams.get('sort'))

  const filters: GalleryFilters = { search, tag, sort }
  const allProjects = await readProjects()
  const filteredProjects = filterProjects(allProjects, filters)
  const allTags = getAllTags(allProjects)

  const ssr = createSSR()
  const body = ssr(renderGallery(filteredProjects, allTags, filters))
  const title = tag ? `Portfolio - ${tag}` : 'Portfolio Gallery'

  return new Response(wrapHtml(body, title), {
    headers: { 'Content-Type': 'text/html; charset=utf-8' },
  })
}

const handleDetailRequest = async (id: string): Promise<Response> => {
  const project = await getProjectById(id)
  const ssr = createSSR()

  if (!project) {
    const body = ssr(renderNotFound())
    return new Response(wrapHtml(body, 'Not Found'), {
      status: 404,
      headers: { 'Content-Type': 'text/html; charset=utf-8' },
    })
  }

  const body = ssr(renderDetail(project))
  return new Response(wrapHtml(body, `${project.title} - Portfolio`), {
    headers: { 'Content-Type': 'text/html; charset=utf-8' },
  })
}

export { handleGalleryRequest, handleDetailRequest }

import { handleGalleryRequest, handleDetailRequest } from './routes'

const PORT = Number(process.env.PORT) || 3000

const server = Bun.serve({
  port: PORT,
  fetch: async (req) => {
    const url = new URL(req.url)
    const path = url.pathname

    // Gallery list view
    if (path === '/' || path === '') {
      return handleGalleryRequest(url)
    }

    // Project detail view
    const detailMatch = path.match(/^\/project\/([a-zA-Z0-9_-]+)$/)
    if (detailMatch) {
      return handleDetailRequest(detailMatch[1])
    }

    // API: get all projects as JSON
    if (path === '/api/projects' && req.method === 'GET') {
      const { readProjects } = await import('./store')
      const projects = await readProjects()
      return Response.json(projects)
    }

    // API: get single project as JSON
    const apiDetailMatch = path.match(/^\/api\/projects\/([a-zA-Z0-9_-]+)$/)
    if (apiDetailMatch && req.method === 'GET') {
      const { getProjectById } = await import('./store')
      const project = await getProjectById(apiDetailMatch[1])
      if (!project) return Response.json({ error: 'Not found' }, { status: 404 })
      return Response.json(project)
    }

    return new Response('Not Found', { status: 404 })
  },
})

console.log(`Portfolio Gallery running at http://localhost:${server.port}`)
